/**
 * SPEC-049: Permisos no concedidos visibles — Alert de error de permiso arriba
 * de la página. Test unitario del wrapper PermissionErrorAlert: pinta el
 * CaptureErrorAlert (título por kind, mensaje del error y botón «Abrir Ajustes
 * del Sistema» hacia el pane del permiso que falló) dentro del contenedor
 * `permission-error-alert`.
 * Frontera de mocking: permissionsService (openPrivacySettings).
 * Generated by QA Dev agent.
 */
import { render, screen, within } from '@testing-library/react'
import userEvent from '@testing-library/user-event'
import { beforeEach, describe, expect, it, vi } from 'vitest'
import { PermissionErrorAlert } from '@/components/recording/PermissionErrorAlert'
import { openPrivacySettings } from '@/services/permissionsService'
import type { CaptureError } from '@/types/audio'

vi.mock('@/services/permissionsService', () => ({
  openPrivacySettings: vi.fn()
}))

const MIC_ERROR: CaptureError = {
  kind: 'microphone-permission',
  message:
    'El permiso de micrófono no está concedido. Concédelo en Ajustes del Sistema → Privacidad y seguridad → Micrófono.'
}

const SYSTEM_ERROR: CaptureError = {
  kind: 'system-audio-permission',
  message:
    'El permiso de captura de audio del sistema no está concedido. Concédelo en Ajustes del Sistema → Privacidad y seguridad → Grabación de pantalla y audio del sistema.'
}

beforeEach(() => {
  vi.clearAllMocks()
  vi.mocked(openPrivacySettings).mockResolvedValue(undefined)
})

describe('PermissionErrorAlert', () => {
  // SPEC-049 · AC-11
  it('shows the error message and an "Abrir Ajustes del Sistema" button that opens the failed permission pane', async () => {
    const user = userEvent.setup()
    const { rerender } = render(<PermissionErrorAlert error={MIC_ERROR} />)

    // Permiso de micrófono: título, mensaje del error y acción hacia su pane
    const container = screen.getByTestId('permission-error-alert')
    expect(within(container).getByText('Permiso de micrófono no concedido')).toBeInTheDocument()
    expect(within(container).getByText(MIC_ERROR.message)).toBeInTheDocument()
    await user.click(
      within(container).getByRole('button', { name: 'Abrir Ajustes del Sistema' })
    )
    expect(vi.mocked(openPrivacySettings)).toHaveBeenLastCalledWith('microphone')

    // Permiso de audio del sistema: mismo contrato, pane de grabación de pantalla
    rerender(<PermissionErrorAlert error={SYSTEM_ERROR} />)
    const systemContainer = screen.getByTestId('permission-error-alert')
    expect(
      within(systemContainer).getByText('Permiso de audio del sistema no concedido')
    ).toBeInTheDocument()
    expect(within(systemContainer).getByText(SYSTEM_ERROR.message)).toBeInTheDocument()
    await user.click(
      within(systemContainer).getByRole('button', { name: 'Abrir Ajustes del Sistema' })
    )
    expect(vi.mocked(openPrivacySettings)).toHaveBeenLastCalledWith('systemAudio')
  })
})
